# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import os
import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_TOPIC_ARN = os.environ.get("DEFAULT_TOPIC_ARN", "")


def _build_message(notification_type, content):
    if isinstance(content, dict):
        payload = content
    else:
        payload = {"message": str(content)}

    if notification_type == "email":
        return {
            "default": payload.get("message", ""),
            "email": payload.get("message", ""),
        }
    if notification_type == "sms":
        return {
            "default": payload.get("message", ""),
            "sms": payload.get("message", ""),
        }
    if notification_type == "push":
        return {
            "default": payload.get("message", ""),
            "GCM": json.dumps({"data": payload}),
            "APNS": json.dumps({"aps": {"alert": payload.get("message", "")}}),
        }
    return {
        "default": payload.get("message", ""),
    }


def lambda_handler(event, context):
    topic_arn = event.get("topic_arn") or DEFAULT_TOPIC_ARN
    if not topic_arn:
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "Missing topic_arn"}),
        }

    notification_type = event.get("notification_type", "default")
    content = event.get("message") or event.get("content") or ""

    message_structure = "json"
    message = _build_message(notification_type, content)

    try:
        response = sns.publish(
            TopicArn=topic_arn,
            Message=json.dumps(message),
            MessageStructure=message_structure,
            Subject=event.get("subject", "Event Notification")[:100] if event.get("subject") else "Event Notification",
        )
        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "message": "Notification published",
                    "message_id": response.get("MessageId"),
                    "topic_arn": topic_arn,
                    "notification_type": notification_type,
                }
            ),
        }
    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Failed to publish notification",
                    "details": str(e),
                }
            ),
        }